-- ============================================================
-- Seed: load legacy mqtt_mqtt taps as test data for the hours
-- analysis page. Original timestamps preserved (June 2024 →
-- September 2025) so set the /hours/ date range to that window
-- to see realistic data. The dashboard will NOT show these — it
-- only reads the last 90 days.
--
-- 540 taps for 3 employees:
--   c679c007f → Brendan Fitzpatrick (~206)
--   7653ab08e → Lee Maddison (~171)
--   7619970f8 → Carl Pickering (~163)
--
-- Idempotent: re-running is safe (employee_cards uses unique
-- card_id; timecard_events guarded with WHERE NOT EXISTS on
-- (card_id, ts) — duplicates from re-run are skipped).
-- ============================================================

-- 1) Card → employee mappings (best-effort by name)
insert into employee_cards (card_id, employee_id, active, notes)
select 'c679c007f', id, true, 'Seeded from legacy mqtt_mqtt dump.'
from employees
where first_name ilike 'B%'
  and last_name  ilike 'Fitz%'
order by active desc, created_at asc
limit 1
on conflict (card_id) do nothing;

insert into employee_cards (card_id, employee_id, active, notes)
select '7653ab08e', id, true, 'Seeded from legacy mqtt_mqtt dump.'
from employees
where first_name ilike 'L%'
  and last_name  ilike 'Maddison%'
order by active desc, created_at asc
limit 1
on conflict (card_id) do nothing;

insert into employee_cards (card_id, employee_id, active, notes)
select '7619970f8', id, true, 'Seeded from legacy mqtt_mqtt dump.'
from employees
where first_name ilike 'C%'
  and last_name  ilike 'Pickering%'
order by active desc, created_at asc
limit 1
on conflict (card_id) do nothing;

-- 2) Tap events (original timestamps, ~14 months of history)
