from (values
  ('2024-06-29 05:59:07+00'::timestamptz, 'carrwood', 'timecard', '7653ab08e', 'legacy', 'tap', 'test', 'carrwood/timecard', jsonb_build_object('legacy_id', 191, 'legacy_scanid', 'LEE MADDISON')),
